body:
Currently verilator tracks the random seed state on classes, but does not keep separate state on processes and rather relies on the thread state.  We should move all state to process based (and if no process use the thread).

This causes UVM tests/01report/90Mantis/3666_report_catcher_random_stab and tests/40phasing/90Mantis/3690_random_stability to fail.

<details>
<summary>Example</summary>

```
// verilog_format: off
`define stop $stop
`define checkd(gotv,expv) do if ((gotv) !== (expv)) begin $write("%%Error: %s:%0d:  got=%0d exp=%0d\n", `__FILE__,`__LINE__, (gotv), (expv)); `stop; end while(0);
`define checks(gotv,expv) do if ((gotv) != (expv)) begin $write("%%Error: %s:%0d:  got='%s' exp='%s'\n", `__FILE__,`__LINE__, (gotv), (expv)); `stop; end while(0);
// verilog_format: on

typedef byte unsigned uint8_t;

class D;
  rand uint8_t x;
endclass

class test;

  D d;

  task run_phase;
    process p;
    uint8_t result;
    string randstate;

    p = process::self();
    p.srandom(100);
    $display("p.randstate = %p",p.get_randstate());  // FIXME remove displays, just for debug
    randstate = p.get_randstate();
    d = new;
    $display("p.randstate = %p",p.get_randstate());
    $display("d.randstate = %p",d.get_randstate());
    void'(d.randomize());
    $display("Pass1 d.x: %h",d.x);
    result = d.x;


    p.srandom(100);
    $display("p.randstate = %p",p.get_randstate());
    d = new;
    $display("p.randstate = %p",p.get_randstate());
    $display("d.randstate = %p",d.get_randstate());
    `checks(p.get_randstate(), randstate);
    void'(d.randomize());
    $display("Pass2 d.x: %h",d.x);
    `checkd(d.x, result);

    p.srandom(100);
    other_task();
    d = new;
    $display("p.randstate = %p",p.get_randstate());
    `checks(p.get_randstate(), randstate);
    void'(d.randomize());
    $display("p.randstate = %p",p.get_randstate());
    $display("d.randstate = %p",d.get_randstate());
    $display("Pass3 d.x: %h",d.x);
    `checkd(d.x, result);
  endtask

  task other_task;
    // verilator no_inline_task
    $display("Other task");
  endtask

endclass

module t;
   initial begin
     test c;
     c = new;
     c.run_phase();
     $finish;
   end
endmodule
```
</details>

